import React, { useEffect, useId, type ReactNode } from 'react';
import { View, StyleSheet } from 'react-native';
import { useGridContext } from '../../Grid/native/GridContext';

export interface IKitsGridItemProps {
  /** Unique identifier — used for context registration. Auto-generated if omitted. */
  id?: string;
  /** Number of grid columns this item spans */
  colSpan: number;
  children?: ReactNode;
}

/**
 * Pure React Native grid item.
 *
 * Registers its colSpan with the parent KitsGrid via context.
 * Reads its calculated pixel width from context and applies it.
 *
 * Does NOT need to be a direct child of KitsGrid — context
 * handles communication regardless of hierarchy depth.
 */
const KitsGridItem = ({ id: externalId, colSpan, children }: IKitsGridItemProps) => {
  const autoId = useId();
  const id = externalId ?? autoId;
  const { registerItem, unregisterItem, getItemWidth, containerWidth } =
    useGridContext();

  // Register on mount and when colSpan changes
  useEffect(() => {
    registerItem(id, colSpan);
  }, [id, colSpan, registerItem]);

  // Unregister on unmount
  useEffect(() => {
    return () => {
      unregisterItem(id);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [id]);

  const width = getItemWidth(id);
  const measured = containerWidth > 0 && width != null;

  return (
    <View
      style={
        measured
          ? { width, flexShrink: 0, flexGrow: 0 }
          : styles.fallback
      }
    >
      {children}
    </View>
  );
};

const styles = StyleSheet.create({
  fallback: {
    width: '100%',
  },
});

export default KitsGridItem;
